package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;
import org.slf4j.LoggerFactory;

import ch.qos.logback.classic.Level;
import ch.qos.logback.classic.Logger;
import ch.qos.logback.classic.LoggerContext;
import ch.qos.logback.classic.spi.ILoggingEvent;
import ch.qos.logback.core.read.ListAppender;

class TripleStoreImportMetricsLoggingTest {

	private TripleStore tripleStore;
	private Logger logger;
	private Level previousLevel;
	private ListAppender<ILoggingEvent> appender;

	@BeforeEach
	void setUp(@TempDir File dataDir) throws Exception {
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc"), null);
		logger = (Logger) LoggerFactory.getLogger(TripleStore.class);
		previousLevel = logger.getLevel();
		logger.setLevel(Level.INFO);

		appender = new ListAppender<>();
		appender.setContext((LoggerContext) LoggerFactory.getILoggerFactory());
		appender.start();
		logger.addAppender(appender);
	}

	@AfterEach
	void tearDown() throws Exception {
		if (appender != null) {
			logger.detachAppender(appender);
			appender.stop();
		}
		if (logger != null) {
			logger.setLevel(previousLevel);
		}
		if (tripleStore != null) {
			tripleStore.close();
		}
	}

	@Test
	void ordinaryWritesDoNotLogImportSpeed() throws Exception {
		tripleStore.startTransaction();
		assertThat(tripleStore.storeTriple(1, 2, 3, 4, true)).isTrue();
		tripleStore.commit();

		List<ILoggingEvent> importSpeedEvents = appender.list.stream()
				.filter(event -> event.getLevel() == Level.INFO)
				.filter(event -> event.getFormattedMessage().contains("LMDB import speed"))
				.collect(Collectors.toList());

		assertThat(importSpeedEvents).isEmpty();
	}
}
